import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from './ui/card';
import { Button } from './ui/button';
import { Badge } from './ui/badge';
import { Avatar, AvatarFallback } from './ui/avatar';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from './ui/select';
import { ArrowLeft, UserPlus, UserMinus, Trophy, Star, Flame, CheckCircle2, ListTodo } from 'lucide-react';
import { toast } from 'sonner@2.0.3';
import { projectId } from '../utils/supabase/info';

export function AssignStudent({ student, classes, onBack, onAssignSuccess, accessToken }) {
  const [selectedClassId, setSelectedClassId] = useState(student.classId || '');
  const [isAssigning, setIsAssigning] = useState(false);
  const [streakData, setStreakData] = useState({ currentStreak: 0, longestStreak: 0, dates: [] });
  const [taskData, setTaskData] = useState({ completedCount: 0, totalCount: 0 });
  const [isLoadingData, setIsLoadingData] = useState(true);

  // Fetch streak and task data
  useEffect(() => {
    const fetchStudentData = async () => {
      setIsLoadingData(true);
      try {
        // Fetch streak data
        const streakResponse = await fetch(
          `https://${projectId}.supabase.co/functions/v1/make-server-2fad19e1/teacher/student-streak/${student.email}`,
          {
            headers: {
              'Authorization': `Bearer ${accessToken}`
            }
          }
        );

        if (streakResponse.ok) {
          const result = await streakResponse.json();
          setStreakData(result.streakData || { currentStreak: 0, longestStreak: 0, dates: [] });
        }

        // Fetch task data
        const tasksResponse = await fetch(
          `https://${projectId}.supabase.co/functions/v1/make-server-2fad19e1/teacher/student-tasks/${student.email}`,
          {
            headers: {
              'Authorization': `Bearer ${accessToken}`
            }
          }
        );

        if (tasksResponse.ok) {
          const result = await tasksResponse.json();
          const tasks = result.tasks || [];
          setTaskData({
            completedCount: tasks.filter(t => t.completed).length,
            totalCount: tasks.length
          });
        }
      } catch (error) {
        console.error('Error fetching student data:', error);
      } finally {
        setIsLoadingData(false);
      }
    };

    if (student && student.email && accessToken) {
      fetchStudentData();
    }
  }, [student, accessToken]);

  const handleAssignToClass = async () => {
    if (!selectedClassId) {
      toast.error('Please select a class');
      return;
    }

    setIsAssigning(true);
    try {
      const selectedClass = classes.find(c => c.id === selectedClassId);

      const response = await fetch(`https://${projectId}.supabase.co/functions/v1/make-server-2fad19e1/teacher/assign-student`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${accessToken}`
        },
        body: JSON.stringify({
          studentId: student.id,
          studentEmail: student.email,
          classId: selectedClassId,
          className: selectedClass.name
        })
      });

      if (response.ok) {
        toast.success(`${student.name} assigned to ${selectedClass.name}`);
        if (onAssignSuccess) {
          onAssignSuccess();
        }
        onBack();
      } else {
        const error = await response.json();
        toast.error(error.error || 'Failed to assign student');
      }
    } catch (error) {
      console.error('Error assigning student:', error);
      toast.error('Failed to assign student');
    } finally {
      setIsAssigning(false);
    }
  };

  const handleUnassign = async () => {
    setIsAssigning(true);
    try {
      const response = await fetch(`https://${projectId}.supabase.co/functions/v1/make-server-2fad19e1/teacher/unassign-student`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${accessToken}`
        },
        body: JSON.stringify({
          studentId: student.id
        })
      });

      if (response.ok) {
        toast.success(`${student.name} unassigned from class`);
        if (onAssignSuccess) {
          onAssignSuccess();
        }
        onBack();
      } else {
        const error = await response.json();
        toast.error(error.error || 'Failed to unassign student');
      }
    } catch (error) {
      console.error('Error unassigning student:', error);
      toast.error('Failed to unassign student');
    } finally {
      setIsAssigning(false);
    }
  };

  return (
    <div className="p-6">
      <div className="mb-6">
        <Button onClick={onBack} variant="ghost" className="mb-4">
          <ArrowLeft className="w-4 h-4 mr-2" />
          Back to Students
        </Button>

        <h1 className="text-2xl font-bold mb-2">Assign Student to Class</h1>
        <p className="text-muted-foreground">
          Manage class assignment for portal-registered student
        </p>
      </div>

      <div className="max-w-2xl">
        {/* Student Info Card */}
        <Card className="mb-6 border-0 shadow-lg bg-gradient-to-br from-purple-50 to-white">
          <CardHeader>
            <CardTitle className="text-lg">Student Information</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex items-center gap-4 mb-4">
              <Avatar className="w-16 h-16 ring-2 ring-purple-200">
                <AvatarFallback className="bg-gradient-to-br from-purple-400 to-blue-500 text-white text-lg">
                  {student.avatar}
                </AvatarFallback>
              </Avatar>
              <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                  <h3 className="font-semibold text-lg">{student.name}</h3>
                  <Badge className="bg-gradient-to-r from-emerald-500 to-teal-500 text-white border-0">
                    Portal User
                  </Badge>
                </div>
                <p className="text-sm text-muted-foreground">{student.email}</p>
              </div>
            </div>

            <div className="grid grid-cols-3 gap-4 p-4 bg-white rounded-lg border">
              <div className="text-center">
                <div className="flex items-center justify-center gap-1 mb-1">
                  <Trophy className="w-4 h-4 text-yellow-500" />
                  <span className="text-sm font-medium">Level</span>
                </div>
                <p className="text-2xl font-bold text-purple-600">{student.currentLevel}</p>
              </div>
              <div className="text-center">
                <div className="flex items-center justify-center gap-1 mb-1">
                  <Star className="w-4 h-4 text-blue-500" />
                  <span className="text-sm font-medium">EXP</span>
                </div>
                <p className="text-2xl font-bold text-blue-600">{student.totalPoints}</p>
              </div>
              <div className="text-center">
                <div className="flex items-center justify-center gap-1 mb-1">
                  <span className="text-sm font-medium">Avg Grade</span>
                </div>
                <p className="text-2xl font-bold text-green-600">{student.averageGrade}%</p>
              </div>
            </div>

            <div className="grid grid-cols-3 gap-4 p-4 bg-white rounded-lg border mt-4">
              <div className="text-center">
                <div className="flex items-center justify-center gap-1 mb-1">
                  <Flame className="w-4 h-4 text-red-500" />
                  <span className="text-sm font-medium">Current Streak</span>
                </div>
                <p className="text-2xl font-bold text-red-600">{streakData.currentStreak}</p>
              </div>
              <div className="text-center">
                <div className="flex items-center justify-center gap-1 mb-1">
                  <CheckCircle2 className="w-4 h-4 text-green-500" />
                  <span className="text-sm font-medium">Longest Streak</span>
                </div>
                <p className="text-2xl font-bold text-green-600">{streakData.longestStreak}</p>
              </div>
              <div className="text-center">
                <div className="flex items-center justify-center gap-1 mb-1">
                  <ListTodo className="w-4 h-4 text-blue-500" />
                  <span className="text-sm font-medium">Tasks</span>
                </div>
                <p className="text-2xl font-bold text-blue-600">{taskData.completedCount}/{taskData.totalCount}</p>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Class Assignment Card */}
        <Card className="border-0 shadow-lg">
          <CardHeader>
            <CardTitle className="text-lg">Class Assignment</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            {student.isAssigned && (
              <div className="p-4 bg-blue-50 rounded-lg border border-blue-200">
                <p className="text-sm font-medium text-blue-900 mb-1">
                  Currently Assigned To:
                </p>
                <p className="text-lg font-semibold text-blue-700">
                  {student.className}
                </p>
              </div>
            )}

            <div className="space-y-2">
              <label className="text-sm font-medium">Select Class</label>
              <Select value={selectedClassId} onValueChange={setSelectedClassId}>
                <SelectTrigger>
                  <SelectValue placeholder="Choose a class..." />
                </SelectTrigger>
                <SelectContent>
                  {classes.length === 0 ? (
                    <div className="p-4 text-center text-sm text-muted-foreground">
                      No classes available. Create a class first.
                    </div>
                  ) : (
                    classes.map((cls) => (
                      <SelectItem key={cls.id} value={cls.id}>
                        {cls.name}
                      </SelectItem>
                    ))
                  )}
                </SelectContent>
              </Select>
            </div>

            <div className="flex gap-3 pt-4">
              <Button
                onClick={handleAssignToClass}
                disabled={isAssigning || !selectedClassId || classes.length === 0}
                className="flex-1 bg-gradient-to-r from-blue-500 to-purple-600 hover:from-blue-600 hover:to-purple-700 text-white border-0"
              >
                <UserPlus className="w-4 h-4 mr-2" />
                {student.isAssigned ? 'Update Assignment' : 'Assign to Class'}
              </Button>

              {student.isAssigned && (
                <Button
                  onClick={handleUnassign}
                  disabled={isAssigning}
                  variant="outline"
                  className="border-red-200 text-red-600 hover:bg-red-50"
                >
                  <UserMinus className="w-4 h-4 mr-2" />
                  Unassign
                </Button>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

src/components/ClassManagement.tsx.content:
import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from './ui/card';
import { Button } from './ui/button';
import { Input } from './ui/input';
import { Badge } from './ui/badge';
import { Search, Users, BookOpen, Plus, Eye, Trash2 } from 'lucide-react';

export function ClassManagement({ classes, onAddClass, onViewClass, onDeleteClass, students = [] }) {
  const [searchTerm, setSearchTerm] = useState('');

  // Calculate real-time student count for each class
  const getStudentCount = (classId) => {
    return students.filter(student => student.classId === classId).length;
  };

  const filteredClasses = classes.filter(classItem =>
    classItem.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    classItem.grade.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (classItem.subject && classItem.subject.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const getGradeColor = (grade) => {
    const gradeNumber = parseInt(grade);
    if (gradeNumber <= 5) return 'bg-gradient-to-r from-green-400 to-emerald-500';
    if (gradeNumber <= 8) return 'bg-gradient-to-r from-blue-400 to-blue-500';
    if (gradeNumber <= 10) return 'bg-gradient-to-r from-purple-400 to-purple-500';
    return 'bg-gradient-to-r from-orange-400 to-red-500';
  };

  return (
    <div className="p-6">
      <div className="mb-6">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6">
          <div>
            <h2 className="text-2xl font-medium">Class Management</h2>
            <p className="text-muted-foreground">Manage your classes and their details</p>
          </div>
          <Button 
            onClick={onAddClass}
            className="bg-gradient-to-r from-blue-500 to-indigo-600 hover:from-blue-600 hover:to-indigo-700 text-white border-0 shadow-md hover:shadow-lg transition-all"
          >
            <Plus className="w-4 h-4 mr-2" />
            Add New Class
          </Button>
        </div>

        <div className="relative max-w-md">
          <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search classes..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10"
          />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredClasses.map((classItem) => (
          <Card key={classItem.id} className="hover:shadow-xl transition-all duration-300 hover:-translate-y-1 border-0 shadow-lg bg-gradient-to-br from-white to-gray-50">
            <CardHeader className="pb-3">
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <CardTitle className="text-lg mb-2">{classItem.name}</CardTitle>
                  <Badge className={`${getGradeColor(classItem.grade)} text-white border-0 mb-2`}>
                    {classItem.grade}
                  </Badge>
                  {classItem.subject && (
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                      <BookOpen className="w-3 h-3" />
                      <span>{classItem.subject}</span>
                    </div>
                  )}
                </div>
              </div>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <div className="p-1 bg-gradient-to-r from-blue-400 to-purple-500 rounded-full">
                    <Users className="w-3 h-3 text-white" />
                  </div>
                  <span className="text-sm font-medium">{getStudentCount(classItem.id)} Students</span>
                </div>
                {classItem.capacity && (
                  <Badge variant="outline" className="text-xs">
                    Capacity: {classItem.capacity}
                  </Badge>
                )}
              </div>

              {classItem.description && (
                <div>
                  <p className="text-sm text-muted-foreground line-clamp-2">
                    {classItem.description}
                  </p>
                </div>
              )}

              <div className="flex gap-2">
                <Button 
                  onClick={() => onViewClass(classItem)}
                  variant="outline"
                  size="sm"
                  className="flex-1 bg-gradient-to-r from-blue-500 to-indigo-600 text-white border-0 hover:from-blue-600 hover:to-indigo-700"
                >
                  <Eye className="w-3 h-3 mr-1" />
                  View Class
                </Button>
                <Button 
                  onClick={() => onDeleteClass(classItem.id)}
                  variant="outline"
                  size="sm"
                  className="text-red-600 hover:text-red-700 hover:bg-red-50"
                >
                  <Trash2 className="w-3 h-3" />
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {filteredClasses.length === 0 && (
        <div className="text-center py-12">
          <div className="p-4 bg-gradient-to-br from-gray-100 to-gray-200 rounded-full w-16 h-16 mx-auto mb-4 flex items-center justify-center">
            <BookOpen className="w-8 h-8 text-gray-400" />
          </div>
          <h3 className="text-lg font-medium mb-2">No Classes Found</h3>
          <p className="text-muted-foreground mb-4">
            {classes.length === 0 
              ? "Get started by creating your first class" 
              : "No classes match your search criteria"
            }
          </p>
          {classes.length === 0 && (
            <Button 
              onClick={onAddClass}
              className="bg-gradient-to-r from-blue-500 to-indigo-600 hover:from-blue-600 hover:to-indigo-700 text-white border-0"
            >
              <Plus className="w-4 h-4 mr-2" />
              Create First Class
            </Button>
          )}
        </div>
      )}
    </div>
  );
}

src/components/Login.tsx.content:
import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from './ui/card';
import { Button } from './ui/button';
import { Input } from './ui/input';
import { Label } from './ui/label';
import { Mail, Lock, Eye, EyeOff, GraduationCap, Loader2, AlertCircle } from 'lucide-react';
import { toast } from 'sonner@2.0.3';
import { ConnectionTest } from './ConnectionTest';

export function Login({ onLogin, onSwitchToSignup }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showConnectionTest, setShowConnectionTest] = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();

    if (!email || !password) {
      toast.error('Please fill in all fields');
      return;
    }

    setIsLoading(true);

    try {
      await onLogin(email, password);
    } catch (error) {
      console.error('Login error:', error);
      setIsLoading(false);
      // Show connection test option if there's a network error
      if (error.message && error.message.includes('fetch')) {
        setShowConnectionTest(true);
      }
    }
  };

  if (showConnectionTest) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-50 via-indigo-50 to-purple-50 p-4">
        <div className="w-full max-w-2xl">
          <Button 
            variant="outline" 
            onClick={() => setShowConnectionTest(false)}
            className="mb-4"
          >
            ← Back to Login
          </Button>
          <ConnectionTest />
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-50 via-indigo-50 to-purple-50 p-4">
      <div className="w-full max-w-md">
        {/* Logo/Header */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-br from-blue-500 to-purple-600 rounded-2xl mb-4 shadow-lg">
            <GraduationCap className="w-10 h-10 text-white" />
          </div>
          <h1 className="text-3xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
            Dental College Portal
          </h1>
          <p className="text-muted-foreground mt-2">Teacher's Admin Panel</p>
        </div>

        <Card className="border-0 shadow-2xl">
          <CardHeader className="space-y-1 pb-4">
            <CardTitle className="text-2xl text-center">Welcome Back!</CardTitle>
            <CardDescription className="text-center">
              Sign in to manage your students and classes
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleLogin} className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="email">Email Address</Label>
                <div className="relative">
                  <Mail className="absolute left-3 top-3 w-4 h-4 text-muted-foreground" />
                  <Input
                    id="email"
                    type="email"
                    placeholder="dr.name@dentalcollege.edu"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="pl-10"
                    disabled={isLoading}
                  />
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="password">Password</Label>
                <div className="relative">
                  <Lock className="absolute left-3 top-3 w-4 h-4 text-muted-foreground" />
                  <Input
                    id="password"
                    type={showPassword ? 'text' : 'password'}
                    placeholder="Enter your password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="pl-10 pr-10"
                    disabled={isLoading}
                  />
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    className="absolute right-0 top-0 h-full px-3 hover:bg-transparent"
                    onClick={() => setShowPassword(!showPassword)}
                    disabled={isLoading}
                  >
                    {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                  </Button>
                </div>
              </div>

              <Button
                type="submit"
                className="w-full bg-gradient-to-r from-blue-500 to-purple-600 hover:from-blue-600 hover:to-purple-700 text-white border-0"
                disabled={isLoading}
              >
                {isLoading ? (
                  <>
                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    Signing in...
                  </>
                ) : (
                  'Sign In'
                )}
              </Button>
            </form>

            <div className="mt-6 text-center">
              <p className="text-sm text-muted-foreground">
                Don't have an account?{' '}
                <button
                  type="button"
                  onClick={onSwitchToSignup}
                  className="text-blue-600 hover:text-blue-700 font-medium hover:underline"
                  disabled={isLoading}
                >
                  Sign up here
                </button>
              </p>
            </div>
          </CardContent>
        </Card>

        {/* Demo Credentials */}
        <div className="mt-6 p-4 bg-white rounded-lg shadow-md border border-blue-100">
          <p className="text-xs text-muted-foreground text-center mb-2">Demo Credentials:</p>
          <p className="text-xs text-center">
            <span className="font-mono bg-blue-50 px-2 py-1 rounded">demo@dentalcollege.edu</span>
            {' / '}
            <span className="font-mono bg-blue-50 px-2 py-1 rounded">demo123</span>
          </p>
        </div>
      </div>
    </div>
  );
}

