                                <Button
                                  onClick={() => startQuiz(task)}
                                  className="bg-gradient-to-r from-indigo-500 to-purple-600 hover:from-indigo-600 hover:to-purple-700 text-white border-0 w-full sm:w-auto"
                                >
                                  <Clock className="w-4 h-4 mr-2" />
